// Pointwise (1x1) conv2d - layer1_0_conv1
// tiled-streaming contract; channel_tile=32; data_in/data_out=256 bits.
//
// Tiling layout
// =============
// IC=64, OC=64, CHANNEL_TILE=32, so IC_TILES = OC_TILES = 2.
// One logical pixel arrives as 2 valid_in beats:
//   beat 0 -> in_latch[ 0..31]
//   beat 1 -> in_latch[32..63]
// One logical pixel emits as 2 valid_out beats:
//   beat 0 -> out_buf[ 0..31] packed into data_out[255:0]
//   beat 1 -> out_buf[32..63] packed into data_out[255:0]
//
// Latency contract
// ================
// pipeline_latency_cycles = 4193 (LayerIR-authoritative).
// MP=4, K_TOTAL=64, OC_PASSES=16, pass_cycles = MP*K_TOTAL + 6 = 262.
// First valid_in beat at cycle 0 -> first valid_out beat at cycle 4193.
//
// Cycle budget:
//   cycle 0    : ST_STREAM_T0 latches input beat 0 (channels  0..31).
//   cycle 1    : ST_STREAM_T1 latches input beat 1 (channels 32..63)
//                AND simultaneously kicks off the very first MAC issue
//                (lane=0, k=0, oc_group=0) because that issue only needs
//                in_latch[0], which beat 0 already provided.
//   cycles 2..256 : ST_RUNNING issues lane=1..3 of k=0, then all (lane,k)
//                   for k=1..63. 256 issues total = MP*K_TOTAL.
//   cycles 257..259 : drain pipeline stages 1 and 2.
//   cycle 260  : ST_BIAS;  cycle 261 : ST_SCALE;  cycle 262 : ST_OUTPUT
//                of pass 0. out_buf[0..3] written; oc_group advances to 1.
//   passes 1..14 each consume 262 cycles via ST_RUNNING/BIAS/SCALE/OUTPUT,
//   each writing the next 4 lanes into out_buf.
//   cycle 4192 : pass 15 ST_OUTPUT writes out_buf[60..63] AND captures
//                packed beat 0 (out_buf[0..31]) into data_out, asserts
//                valid_out, and transitions to ST_EMIT_BEAT1.
//   cycle 4193 : data_out shows beat 0; valid_out=1.  ST_EMIT_BEAT1 packs
//                out_buf[32..63] into data_out and asserts valid_out.
//   cycle 4194 : data_out shows beat 1; valid_out=1.  Returns to
//                ST_STREAM_T0 with ready_in=1 for the next pixel.
//
// MAC pipeline (3 stages from issue to acc-write), unchanged from the
// pointwise reference: one synchronous ROM read, one registered DSP
// multiply (use_dsp), one indexed accumulator write.

module layer1_0_conv1 (
    input  wire              clk,
    input  wire              rst_n,
    input  wire              valid_in,
    output reg               ready_in,
    input  wire [255:0]      data_in,
    output reg               valid_out,
    output reg  [255:0]      data_out
);
    localparam IC           = 64;
    localparam OC           = 64;
    localparam IH           = 112;
    localparam IW           = 112;
    localparam OH           = 112;
    localparam OW           = 112;
    localparam KH           = 1;
    localparam KW           = 1;
    localparam SH           = 1;
    localparam SW           = 1;
    localparam PH           = 0;
    localparam PW           = 0;
    localparam K_TOTAL      = IC * KH * KW;
    localparam MP           = 4;
    localparam OC_PASSES    = (OC + MP - 1) / MP;
    localparam CHANNEL_TILE = 32;
    localparam IC_TILES     = (IC + CHANNEL_TILE - 1) / CHANNEL_TILE;
    localparam OC_TILES     = (OC + CHANNEL_TILE - 1) / CHANNEL_TILE;

    localparam NUM_WEIGHTS    = OC * K_TOTAL;
    localparam WEIGHT_ADDR_W  = (NUM_WEIGHTS <= 1) ? 1 : $clog2(NUM_WEIGHTS);
    localparam OC_INDEX_W     = (OC + MP <= 1) ? 1 : $clog2(OC + MP);

    localparam SCALE_MULT  = 29009;
    localparam SCALE_SHIFT = 20;

    localparam integer PROD_W        = 16;
    localparam integer ACC_W         = PROD_W + $clog2(K_TOTAL);
    localparam integer BIAS_W        = 32;
    localparam integer BIASED_W      = ((ACC_W > BIAS_W) ? ACC_W : BIAS_W) + 1;
    localparam integer SCALE_MAG_W   = $clog2(SCALE_MULT + 1);
    localparam integer SCALE_CONST_W = SCALE_MAG_W + 1;
    localparam integer SCALED_W      = BIASED_W + SCALE_CONST_W;
    localparam signed [SCALE_CONST_W-1:0] SCALE_MULT_CONST = SCALE_MULT;
    localparam signed [SCALED_W-1:0] SCALE_ROUND_BIAS =
        {{(SCALED_W-1){1'b0}}, 1'b1} <<< (SCALE_SHIFT - 1);

    localparam ST_STREAM_T0  = 3'd0;
    localparam ST_STREAM_T1  = 3'd1;
    localparam ST_RUNNING    = 3'd2;
    localparam ST_BIAS       = 3'd3;
    localparam ST_SCALE      = 3'd4;
    localparam ST_OUTPUT     = 3'd5;
    localparam ST_EMIT_BEAT1 = 3'd6;

    (* rom_style = "block", ram_style = "block" *) reg signed [7:0]  weights [0:OC*K_TOTAL-1];
    (* rom_style = "block", ram_style = "block" *) reg signed [31:0] biases  [0:OC-1];
    initial begin
        $readmemh("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/layer1_0_conv1_weights.hex", weights);
        $readmemh("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/layer1_0_conv1_bias.hex", biases);
    end

    reg signed [7:0] in_latch [0:IC-1];
    reg signed [7:0] out_buf  [0:OC-1];

    reg signed [ACC_W-1:0]    acc    [0:MP-1];
    reg signed [BIASED_W-1:0] biased [0:MP-1];
    reg signed [SCALED_W-1:0] scaled [0:MP-1];
    reg signed [SCALED_W-1:0] v_tmp;

    reg [$clog2(K_TOTAL+1)-1:0]   k_counter;
    reg [$clog2(MP+1)-1:0]        lane_counter;
    reg [$clog2(OC_PASSES+1)-1:0] oc_group;
    reg [2:0] state;

    reg  signed [7:0]              weight_q;
    wire [OC_INDEX_W-1:0]          current_global_oc;
    wire [WEIGHT_ADDR_W-1:0]       weight_read_addr;
    assign current_global_oc = oc_group * MP + lane_counter;
    assign weight_read_addr  = current_global_oc * K_TOTAL + k_counter;

    always @(posedge clk) begin
        weight_q <= weights[weight_read_addr];
    end

    reg                            mac_valid_q1;
    reg [$clog2(MP+1)-1:0]         mac_lane_q1;
    reg [$clog2(K_TOTAL+1)-1:0]    mac_k_q1;
    reg [OC_INDEX_W-1:0]           mac_global_oc_q1;
    reg                            mac_done_issuing;

    reg                            mac_valid_q2;
    reg [$clog2(MP+1)-1:0]         mac_lane_q2;
    reg [OC_INDEX_W-1:0]           mac_global_oc_q2;

    (* use_dsp = "yes" *) reg signed [PROD_W-1:0] mul_q;

    integer i, lane, ch;
    integer bias_oc;
    integer out_oc;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state            <= ST_STREAM_T0;
            ready_in         <= 1'b1;  // [INVARIANT:READY_IN_GATING]
            valid_out        <= 1'b0;
            k_counter        <= 0;
            lane_counter     <= 0;
            oc_group         <= 0;
            data_out         <= 256'd0;
            mac_valid_q1     <= 1'b0;
            mac_lane_q1      <= 0;
            mac_k_q1         <= 0;
            mac_global_oc_q1 <= 0;
            mac_valid_q2     <= 1'b0;
            mac_lane_q2      <= 0;
            mac_global_oc_q2 <= 0;
            mac_done_issuing <= 1'b0;
            mul_q            <= 0;
            for (i = 0; i < IC; i = i + 1)
                in_latch[i] <= 8'sd0;
            for (i = 0; i < OC; i = i + 1)
                out_buf[i]  <= 8'sd0;
            for (lane = 0; lane < MP; lane = lane + 1) begin
                acc   [lane] <= 0;
                biased[lane] <= 0;
                scaled[lane] <= 0;
            end
        end else begin
            mul_q            <= $signed(weight_q) * $signed(in_latch[mac_k_q1]);
            mac_valid_q2     <= mac_valid_q1;
            mac_lane_q2      <= mac_lane_q1;
            mac_global_oc_q2 <= mac_global_oc_q1;

            if (mac_valid_q2 && mac_global_oc_q2 < OC) begin
                acc[mac_lane_q2] <= acc[mac_lane_q2] + $signed(mul_q);
            end

            case (state)

            ST_STREAM_T0: begin
                valid_out    <= 1'b0;
                mac_valid_q1 <= 1'b0;
                if (valid_in) begin
                    for (ch = 0; ch < CHANNEL_TILE; ch = ch + 1)
                        in_latch[ch] <= $signed(data_in[ch*8 +: 8]);
                    ready_in <= 1'b1;  // [INVARIANT:READY_IN_GATING]
                    state    <= ST_STREAM_T1;
                end
            end

            ST_STREAM_T1: begin
                valid_out <= 1'b0;
                if (valid_in) begin
                    for (ch = 0; ch < CHANNEL_TILE; ch = ch + 1)
                        in_latch[CHANNEL_TILE + ch] <= $signed(data_in[ch*8 +: 8]);
                    ready_in         <= 1'b0;  // [INVARIANT:READY_IN_GATING]
                    k_counter        <= 0;
                    lane_counter     <= 1;
                    oc_group         <= 0;
                    mac_done_issuing <= 1'b0;
                    for (lane = 0; lane < MP; lane = lane + 1)
                        acc[lane] <= 0;
                    mac_lane_q1      <= 0;
                    mac_k_q1         <= 0;
                    mac_global_oc_q1 <= 0;
                    mac_valid_q1     <= 1'b1;
                    state            <= ST_RUNNING;
                end
            end

            ST_RUNNING: begin
                if (mac_done_issuing) begin
                    mac_valid_q1 <= 1'b0;
                    if (!mac_valid_q1 && !mac_valid_q2) begin
                        mac_done_issuing <= 1'b0;
                        state            <= ST_BIAS;
                    end
                end else begin
                    mac_lane_q1      <= lane_counter;
                    mac_k_q1         <= k_counter;
                    mac_global_oc_q1 <= current_global_oc;
                    mac_valid_q1     <= 1'b1;

                    if (lane_counter == MP - 1) begin
                        lane_counter <= 0;
                        if (k_counter == K_TOTAL - 1) begin
                            mac_done_issuing <= 1'b1;
                        end else begin
                            k_counter <= k_counter + 1;
                        end
                    end else begin
                        lane_counter <= lane_counter + 1;
                    end
                end
            end

            ST_BIAS: begin
                for (lane = 0; lane < MP; lane = lane + 1) begin
                    bias_oc = oc_group * MP + lane;
                    if (bias_oc < OC)
                        biased[lane] <= $signed(acc[lane]) + $signed(biases[bias_oc]);
                    else
                        biased[lane] <= 0;
                end
                state <= ST_SCALE;
            end

            ST_SCALE: begin
                for (lane = 0; lane < MP; lane = lane + 1)
                    scaled[lane] <= $signed(biased[lane]) * $signed(SCALE_MULT_CONST);
                state <= ST_OUTPUT;
            end

            ST_OUTPUT: begin
                for (lane = 0; lane < MP; lane = lane + 1) begin
                    out_oc = oc_group * MP + lane;
                    if (out_oc < OC) begin
                        // [INVARIANT:ROUNDING]
                        v_tmp = (scaled[lane] + SCALE_ROUND_BIAS) >>> SCALE_SHIFT;
                        out_buf[out_oc] <= (v_tmp >  127) ?  8'sd127 :
                                           (v_tmp < -128) ? -8'sd128 :
                                                            v_tmp[7:0];
                    end
                end

                if (oc_group == OC_PASSES - 1) begin
                    for (ch = 0; ch < CHANNEL_TILE; ch = ch + 1)
                        data_out[ch*8 +: 8] <= out_buf[ch];
                    valid_out <= 1'b1;  // [INVARIANT:VALID_OUT_LATENCY]
                    state     <= ST_EMIT_BEAT1;
                end else begin
                    oc_group         <= oc_group + 1;
                    k_counter        <= 0;
                    lane_counter     <= 0;
                    mac_done_issuing <= 1'b0;
                    for (lane = 0; lane < MP; lane = lane + 1)
                        acc[lane] <= 0;
                    state <= ST_RUNNING;
                end
            end

            ST_EMIT_BEAT1: begin
                for (ch = 0; ch < CHANNEL_TILE; ch = ch + 1)
                    data_out[ch*8 +: 8] <= out_buf[CHANNEL_TILE + ch];
                valid_out <= 1'b1;
                ready_in  <= 1'b1;
                state     <= ST_STREAM_T0;
            end

            default: state <= ST_STREAM_T0;
            endcase
        end
    end
endmodule
